struct NetPacketBuilder {
  typedef NetPacket Table;
  ::flatbuffers::FlatBufferBuilder &fbb_;
  ::flatbuffers::uoffset_t start_;
  void add_payload_type(fbs::NetPayload payload_type) {
    fbb_.AddElement<uint8_t>(NetPacket::VT_PAYLOAD_TYPE, static_cast<uint8_t>(payload_type), 0);
  }
  void add_payload(::flatbuffers::Offset<void> payload) {
    fbb_.AddOffset(NetPacket::VT_PAYLOAD, payload);
  }
  explicit NetPacketBuilder(::flatbuffers::FlatBufferBuilder &_fbb)
        : fbb_(_fbb) {
    start_ = fbb_.StartTable();
  }
  ::flatbuffers::Offset<NetPacket> Finish() {
    const auto end = fbb_.EndTable(start_);
    auto o = ::flatbuffers::Offset<NetPacket>(end);
    return o;
  }
};

inline ::flatbuffers::Offset<NetPacket> CreateNetPacket(
    ::flatbuffers::FlatBufferBuilder &_fbb,
    fbs::NetPayload payload_type = fbs::NetPayload_NONE,
    ::flatbuffers::Offset<void> payload = 0) {
  NetPacketBuilder builder_(_fbb);
  builder_.add_payload(payload);
  builder_.add_payload_type(payload_type);
  return builder_.Finish();
}

::flatbuffers::Offset<NetPacket> CreateNetPacket(::flatbuffers::FlatBufferBuilder &_fbb, const NetPacketT *_o, const ::flatbuffers::rehasher_function_t *_rehasher = nullptr);

inline NetPacketT *NetPacket::UnPack(const ::flatbuffers::resolver_function_t *_resolver) const {
  auto _o = std::unique_ptr<NetPacketT>(new NetPacketT());
  UnPackTo(_o.get(), _resolver);
  return _o.release();
}

inline void NetPacket::UnPackTo(NetPacketT *_o, const ::flatbuffers::resolver_function_t *_resolver) const {
  (void)_o;
  (void)_resolver;
  { auto _e = payload_type(); _o->payload.type = _e; }
  { auto _e = payload(); if (_e) _o->payload.value = fbs::NetPayloadUnion::UnPack(_e, payload_type(), _resolver); }
}

inline ::flatbuffers::Offset<NetPacket> CreateNetPacket(::flatbuffers::FlatBufferBuilder &_fbb, const NetPacketT *_o, const ::flatbuffers::rehasher_function_t *_rehasher) {
  return NetPacket::Pack(_fbb, _o, _rehasher);
}

inline ::flatbuffers::Offset<NetPacket> NetPacket::Pack(::flatbuffers::FlatBufferBuilder &_fbb, const NetPacketT* _o, const ::flatbuffers::rehasher_function_t *_rehasher) {
  (void)_rehasher;
  (void)_o;
  struct _VectorArgs { ::flatbuffers::FlatBufferBuilder *__fbb; const NetPacketT* __o; const ::flatbuffers::rehasher_function_t *__rehasher; } _va = { &_fbb, _o, _rehasher}; (void)_va;
  auto _payload_type = _o->payload.type;
  auto _payload = _o->payload.Pack(_fbb);
  return fbs::CreateNetPacket(
      _fbb,
      _payload_type,
      _payload);
}

template <bool B>
inline bool VerifyNetPayload(::flatbuffers::VerifierTemplate<B> &verifier, const void *obj, NetPayload type) {
  switch (type) {
    case NetPayload_NONE: {
      return true;
    }
    case NetPayload_ClientHeartbeat: {
      auto ptr = reinterpret_cast<const fbs::ClientHeartbeat *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ClientScene: {
      auto ptr = reinterpret_cast<const fbs::ClientScene *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ClientCharacterLogic: {
      auto ptr = reinterpret_cast<const fbs::ClientCharacterLogic *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ClientCharacterAttack: {
      auto ptr = reinterpret_cast<const fbs::ClientCharacterAttack *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ClientCharacterSkill: {
      auto ptr = reinterpret_cast<const fbs::ClientCharacterSkill *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ClientCharacterBall: {
      auto ptr = reinterpret_cast<const fbs::ClientCharacterBall *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ClientMobAttack: {
      auto ptr = reinterpret_cast<const fbs::ClientMobAttack *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ClientCharacterChat: {
      auto ptr = reinterpret_cast<const fbs::ClientCharacterChat *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerHeartbeat: {
      auto ptr = reinterpret_cast<const fbs::ServerHeartbeat *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerScene: {
      auto ptr = reinterpret_cast<const fbs::ServerScene *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerCharacterIn: {
      auto ptr = reinterpret_cast<const fbs::ServerCharacterIn *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerCharacterOut: {
      auto ptr = reinterpret_cast<const fbs::ServerCharacterOut *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerCharacterLogic: {
      auto ptr = reinterpret_cast<const fbs::ServerCharacterLogic *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerCharacterAttack: {
      auto ptr = reinterpret_cast<const fbs::ServerCharacterAttack *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerCharacterSkill: {
      auto ptr = reinterpret_cast<const fbs::ServerCharacterSkill *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerCharacterBall: {
      auto ptr = reinterpret_cast<const fbs::ServerCharacterBall *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerMobLogic: {
      auto ptr = reinterpret_cast<const fbs::ServerMobLogic *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case NetPayload_ServerMobAttack: {
      auto ptr = reinterpret_cast<const fbs::ServerMobAttack *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

template <bool B>
inline bool VerifyNetPayloadVector(::flatbuffers::VerifierTemplate<B> &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<uint8_t> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyNetPayload(
        verifier,  values->Get(i), types->GetEnum<NetPayload>(i))) {
      return false;
    }
  }
  return true;
}

